import { By } from "selenium-webdriver";
import ojwd, { DriverLike, register } from "../../";
import { OjTagCloud } from "./OjTagCloud";
export { OjTagCloud };

/**
 * Create an instance of [[OjTagCloud]].  This function will first wait for
 * the element to appear in the DOM before trying to locate it.
 * @example
 * <code>
 * const el = await ojTagCloud(driver, By.id('my-oj-tag-cloud'))
 * </code>
 * @param driver A WebDriver/WebElement instance used to locate the component
 * element.
 * @param by The By locator with which to find the element
 */
export async function ojTagCloud(driver: DriverLike, by: By): Promise<OjTagCloud> {
  const webEl = await driver.findElement(by);
  // Check that the element is of type OjTagCloud
  if (!(webEl instanceof OjTagCloud)) {
    const tagName = await webEl.getTagName();
    throw Error(`Locator '${by}' located a <${tagName}>, but expected <oj-tag-cloud>`);
  }
  return webEl;
}

register("oj-tag-cloud", OjTagCloud);
